def connect_wifi(ssid, password, timeout_s=20):
    if network is None:
        return False
    wlan = network.WLAN(network.STA_IF)
    if not wlan.active():
        wlan.active(True)
    if wlan.isconnected():
        return True
    wlan.connect(ssid, password)
    t0 = time.time()
    while not wlan.isconnected() and (time.time() - t0) < timeout_s:
        time.sleep(0.2)
    return wlan.isconnected()


